"use client";

import * as React from "react";
import {
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Checkbox,
  Form,
  FormDescription,
  FormField,
  FormGroup,
  FormLabel,
  FormMessage,
  Input,
  PasswordInput,
  PasswordRequirementList,
  type PasswordRequirement,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  TextLink,
} from "@gunjo/ui";

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function LoginPage() {
  const [tab, setTab] = React.useState<"sign-in" | "create">("sign-in");

  // ---- Sign in state ----
  const [siEmail, setSiEmail] = React.useState("");
  const [siPassword, setSiPassword] = React.useState("");
  const [remember, setRemember] = React.useState(false);
  const [siSubmitted, setSiSubmitted] = React.useState(false);

  // ---- Create account state ----
  const [name, setName] = React.useState("");
  const [email, setEmail] = React.useState("");
  const [password, setPassword] = React.useState("");
  const [confirm, setConfirm] = React.useState("");
  const [caSubmitted, setCaSubmitted] = React.useState(false);

  // Sign-in validation
  const siEmailError =
    siSubmitted && !siEmail
      ? "メールアドレスを入力してください。"
      : siSubmitted && !EMAIL_RE.test(siEmail)
        ? "有効なメールアドレスを入力してください。"
        : null;
  const siPasswordError =
    siSubmitted && !siPassword ? "パスワードを入力してください。" : null;

  // Create-account validation
  const requirements: PasswordRequirement[] = [
    { id: "len", label: "8文字以上", met: password.length >= 8 },
    {
      id: "case",
      label: "大文字と小文字を含む",
      met: /[a-z]/.test(password) && /[A-Z]/.test(password),
    },
    { id: "num", label: "数字を含む", met: /\d/.test(password) },
  ];
  const passwordOk = requirements.every((r) => r.met);

  const caNameError = caSubmitted && !name ? "お名前を入力してください。" : null;
  const caEmailError =
    caSubmitted && !email
      ? "メールアドレスを入力してください。"
      : caSubmitted && !EMAIL_RE.test(email)
        ? "有効なメールアドレスを入力してください。"
        : null;
  const caPasswordError =
    caSubmitted && !passwordOk
      ? "パスワードが要件を満たしていません。"
      : null;
  const caConfirmError =
    caSubmitted && confirm !== password ? "パスワードが一致しません。" : null;

  const handleSignIn = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setSiSubmitted(true);
  };

  const handleCreate = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setCaSubmitted(true);
  };

  return (
    <main className="flex min-h-screen items-center justify-center bg-background px-4 py-10 text-foreground">
      <div className="flex w-full max-w-md flex-col gap-6">
        <header className="flex flex-col items-center gap-1 text-center">
          <h1 className="text-2xl font-semibold tracking-tight">Gunjo Studio</h1>
          <p className="text-sm text-muted-foreground">
            続けるには、ログインまたはアカウントを作成してください。
          </p>
        </header>

        <Tabs
          value={tab}
          onValueChange={(v) => setTab(v as "sign-in" | "create")}
          className="w-full border-0 p-0"
        >
          <TabsList className="w-full">
            <TabsTrigger value="sign-in" className="flex-1">
              ログイン
            </TabsTrigger>
            <TabsTrigger value="create" className="flex-1">
              アカウント作成
            </TabsTrigger>
          </TabsList>

          {/* ---------------- Sign in ---------------- */}
          <TabsContent value="sign-in" className="px-0">
            <Card>
              <Form onSubmit={handleSignIn} noValidate>
                <CardHeader>
                  <CardTitle>おかえりなさい</CardTitle>
                  <CardDescription>
                    ワークスペースにアクセスするには、認証情報を入力してください。
                  </CardDescription>
                </CardHeader>

                <CardContent className="flex flex-col gap-5">
                  <FormField className="p-0">
                    <FormGroup>
                      <FormLabel htmlFor="si-email">メールアドレス</FormLabel>
                      <Input
                        id="si-email"
                        type="email"
                        autoComplete="email"
                        placeholder="you@example.com"
                        value={siEmail}
                        onChange={(e) => setSiEmail(e.target.value)}
                        aria-invalid={Boolean(siEmailError)}
                      />
                      {siEmailError ? (
                        <FormMessage>{siEmailError}</FormMessage>
                      ) : null}
                    </FormGroup>
                  </FormField>

                  <FormField className="p-0">
                    <FormGroup>
                      <div className="flex items-center justify-between">
                        <FormLabel htmlFor="si-password">パスワード</FormLabel>
                        <TextLink href="#" className="text-xs">
                          パスワードをお忘れですか？
                        </TextLink>
                      </div>
                      <PasswordInput
                        id="si-password"
                        autoComplete="current-password"
                        placeholder="パスワード"
                        value={siPassword}
                        onChange={(e) => setSiPassword(e.target.value)}
                        aria-invalid={Boolean(siPasswordError)}
                      />
                      {siPasswordError ? (
                        <FormMessage>{siPasswordError}</FormMessage>
                      ) : null}
                    </FormGroup>
                  </FormField>

                  <label className="flex items-center gap-2 text-sm">
                    <Checkbox
                      checked={remember}
                      onCheckedChange={setRemember}
                      aria-label="ログイン状態を保存"
                    />
                    <span>このデバイスでログイン状態を保存する</span>
                  </label>

                  <Button type="submit" variant="primary" className="w-full">
                    ログイン
                  </Button>
                </CardContent>
              </Form>
            </Card>
          </TabsContent>

          {/* ---------------- Create account ---------------- */}
          <TabsContent value="create" className="px-0">
            <Card>
              <Form onSubmit={handleCreate} noValidate>
                <CardHeader>
                  <CardTitle>アカウントを作成</CardTitle>
                  <CardDescription>
                    無料のワークスペースで始めましょう。
                  </CardDescription>
                </CardHeader>

                <CardContent className="flex flex-col gap-5">
                  <FormField className="p-0">
                    <FormGroup>
                      <FormLabel htmlFor="ca-name">お名前</FormLabel>
                      <Input
                        id="ca-name"
                        autoComplete="name"
                        placeholder="山田 花子"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        aria-invalid={Boolean(caNameError)}
                      />
                      {caNameError ? (
                        <FormMessage>{caNameError}</FormMessage>
                      ) : null}
                    </FormGroup>
                  </FormField>

                  <FormField className="p-0">
                    <FormGroup>
                      <FormLabel htmlFor="ca-email">メールアドレス</FormLabel>
                      <Input
                        id="ca-email"
                        type="email"
                        autoComplete="email"
                        placeholder="you@example.com"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        aria-invalid={Boolean(caEmailError)}
                      />
                      {caEmailError ? (
                        <FormMessage>{caEmailError}</FormMessage>
                      ) : null}
                    </FormGroup>
                  </FormField>

                  <FormField className="p-0">
                    <FormGroup>
                      <FormLabel htmlFor="ca-password">パスワード</FormLabel>
                      <PasswordInput
                        id="ca-password"
                        autoComplete="new-password"
                        placeholder="パスワードを作成"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        aria-invalid={Boolean(caPasswordError)}
                      />
                      <FormDescription>
                        英字と数字を組み合わせた8文字以上のパスワードを設定してください。
                      </FormDescription>
                      {password ? (
                        <PasswordRequirementList
                          className="mt-1"
                          requirements={requirements}
                        />
                      ) : null}
                      {caPasswordError ? (
                        <FormMessage>{caPasswordError}</FormMessage>
                      ) : null}
                    </FormGroup>
                  </FormField>

                  <FormField className="p-0">
                    <FormGroup>
                      <FormLabel htmlFor="ca-confirm">
                        パスワード（確認）
                      </FormLabel>
                      <PasswordInput
                        id="ca-confirm"
                        autoComplete="new-password"
                        placeholder="パスワードを再入力"
                        value={confirm}
                        onChange={(e) => setConfirm(e.target.value)}
                        aria-invalid={Boolean(caConfirmError)}
                      />
                      {caConfirmError ? (
                        <FormMessage>{caConfirmError}</FormMessage>
                      ) : null}
                    </FormGroup>
                  </FormField>

                  <Button type="submit" variant="primary" className="w-full">
                    アカウントを作成
                  </Button>
                </CardContent>
              </Form>
            </Card>
          </TabsContent>
        </Tabs>

        <p className="text-center text-xs text-muted-foreground">
          続行することで、
          <TextLink href="#" className="text-xs">
            利用規約
          </TextLink>
          および
          <TextLink href="#" className="text-xs">
            プライバシーポリシー
          </TextLink>
          に同意したものとみなされます。
        </p>
      </div>
    </main>
  );
}
